package day4;

public class Program5_BreakKey {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		System.out.println("Hello");
		for (int i = 0; i <= 10; i++) {
			if (i == 5) {
				break;
			}
			System.out.print(i + " ");
			

		}
		System.out.println("\nBye");
	}

}
